def now_iso() -> str:
    return datetime.utcnow().isoformat() + "Z"

def save_upload_file(upload_file: UploadFile, directory: str) -> str:
    os.makedirs(directory, exist_ok=True)
    ext = os.path.splitext(upload_file.filename or "")[1].lower()
    name = f"{uuid.uuid4().hex}{ext}"
    path = os.path.join(directory, name)
    with open(path, "wb") as f:
        shutil.copyfileobj(upload_file.file, f)
    return path

def safe_load_csv(csv_path: str) -> pd.DataFrame:
    if not os.path.exists(csv_path):
        raise HTTPException(status_code=404, detail="CSV file not found")
    try:
        return pd.read_csv(csv_path)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to load CSV: {e}")

def build_tabular_model(input_dim: int, num_classes: int) -> keras.Model:
    inputs = keras.Input(shape=(input_dim,), name="features")
    x = layers.Normalization()(inputs)
    x = layers.Dense(128, activation="relu")(x)
    x = layers.Dropout(0.2)(x)
    x = layers.Dense(64, activation="relu")(x)
    x = layers.Dropout(0.2)(x)
    if num_classes == 2:
        outputs = layers.Dense(1, activation="sigmoid")(x)
        loss = "binary_crossentropy"
        metrics = ["accuracy"]
    else:
        outputs = layers.Dense(num_classes, activation="softmax")(x)
        loss = "sparse_categorical_crossentropy"
        metrics = ["accuracy"]
    model = keras.Model(inputs, outputs, name="tabular_classifier")
    model.compile(optimizer="adam", loss=loss, metrics=metrics)
    return model

def build_image_model(num_classes: int) -> keras.Model:
    base = keras.applications.MobileNetV2(
        input_shape=IMAGE_SIZE + (3,),
        include_top=False,
        weights="imagenet",
    )
    base.trainable = False
    inputs = keras.Input(shape=IMAGE_SIZE + (3,), name="image")
    x = keras.applications.mobilenet_v2.preprocess_input(inputs)
    x = base(x, training=False)
    x = layers.GlobalAveragePooling2D()(x)
    x = layers.Dropout(0.2)(x)
    if num_classes == 2:
        outputs = layers.Dense(1, activation="sigmoid")(x)
        loss = "binary_crossentropy"
        metrics = ["accuracy"]
    else:
        outputs = layers.Dense(num_classes, activation="softmax")(x)
        loss = "sparse_categorical_crossentropy"
        metrics = ["accuracy"]
    model = keras.Model(inputs, outputs, name="image_classifier")
    model.compile(optimizer=keras.optimizers.Adam(1e-4), loss=loss, metrics=metrics)
    return model

def load_model_if_exists() -> Optional[keras.Model]:
    global CURRENT_MODEL
    with MODEL_LOCK:
        if CURRENT_MODEL is not None:
            return CURRENT_MODEL
        if os.path.exists(CURRENT_MODEL_PATH):
            CURRENT_MODEL = keras.models.load_model(CURRENT_MODEL_PATH)
            return CURRENT_MODEL
        return None

def save_model(model: keras.Model, meta: dict) -> None:
    global CURRENT_MODEL
    with MODEL_LOCK:
        model.save(CURRENT_MODEL_PATH)
        with open(MODEL_META_PATH, "w", encoding="utf-8") as f:
            json.dump(meta, f, indent=2)
        CURRENT_MODEL = model

def list_image_files(directory: str) -> Tuple[List[str], List[int], List[str]]:
    class_names = []
    paths = []
    labels = []
    for idx, cls in enumerate(sorted([d for d in os.listdir(directory) if os.path.isdir(os.path.join(directory, d))])):
        class_names.append(cls)
        cls_dir = os.path.join(directory, cls)
        for fn in os.listdir(cls_dir):
            p = os.path.join(cls_dir, fn)
            if os.path.isfile(p) and fn.lower().endswith((".jpg", ".jpeg", ".png", ".bmp", ".webp")):
                paths.append(p)
                labels.append(idx)
    return paths, labels, class_names

def load_image(path: str) -> np.ndarray:
    img = Image.open(path).convert("RGB").resize(IMAGE_SIZE)
    arr = np.asarray(img).astype(np.float32)
    return arr

def train_tabular_from_csv(csv_path: str, label_column: str, feature_columns: Optional[List[str]], epochs: int, batch_size: int, validation_split: float):
    df = safe_load_csv(csv_path)
    if label_column not in df.columns:
        raise HTTPException(status_code=400, detail=f"Label column '{label_column}' not found")
    if feature_columns is None:
        feature_columns = [c for c in df.columns if c != label_column]
    missing = [c for c in feature_columns if c not in df.columns]
    if missing:
        raise HTTPException(status_code=400, detail=f"Missing feature columns: {missing}")
    X = df[feature_columns].copy()
    y_raw = df[label_column].copy()
    if X.isnull().any().any():
        X = X.fillna(X.mean(numeric_only=True))
    if y_raw.dtype == object:
        y_cat = pd.Categorical(y_raw)
        y = y_cat.codes.astype(np.int32)
        class_names = list(y_cat.categories)
    else:
        y = y_raw.astype(np.int32).to_numpy()
        class_names = sorted(np.unique(y).tolist())
    X = X.astype(np.float32).to_numpy()
    num_classes = len(np.unique(y))
    model = build_tabular_model(X.shape[1], num_classes)
    history = model.fit(
        X,
        y,
        epochs=epochs,
        batch_size=batch_size,
        validation_split=validation_split,
        verbose=0,
    )
    meta = {
        "type": "tabular",
        "trained_at": now_iso(),
        "csv_path": csv_path,
        "label_column": label_column,
        "feature_columns": feature_columns,
        "class_names": [str(c) for c in class_names],
        "history": {k: [float(v) for v in vals] for k, vals in history.history.items()},
    }
    save_model(model, meta)
    return meta

def image_dataset_from_directory_custom(directory: str, validation_split: float, seed: int = 42):
    return tf.keras.utils.image_dataset_from_directory(
        directory,
        labels="inferred",
        label_mode="int",
        image_size=IMAGE_SIZE,
        batch_size=32,
        validation_split=validation_split if validation_split > 0 else None,
        subset="training" if validation_split > 0 else None,
        seed=seed,
        shuffle=True,
    )

def train_image_from_directory(directory: str, epochs: int, batch_size: int, validation_split: float):
    if not os.path.isdir(directory):
        raise HTTPException(status_code=404, detail="Image dataset directory not found")
    train_ds = tf.keras.utils.image_dataset_from_directory(
        directory,
        labels="inferred",
        label_mode="int",
        image_size=IMAGE_SIZE,
        batch_size=batch_size,
        validation_split=validation_split,
        subset="training",
        seed=42,
        shuffle=True,
    )
    val_ds = tf.keras.utils.image_dataset_from_directory(
        directory,
        labels="inferred",
        label_mode="int",
        image_size=IMAGE_SIZE,
        batch_size=batch_size,
        validation_split=validation_split,
        subset="validation",
        seed=42,
        shuffle=True,
    )
    class_names = train_ds.class_names
    AUTOTUNE = tf.data.AUTOTUNE
    train_ds = train_ds.prefetch(buffer_size=AUTOTUNE)
    val_ds = val_ds.prefetch(buffer_size=AUTOTUNE)
    num_classes = len(class_names)
    model = build_image_model(num_classes)
    callbacks = [
        keras.callbacks.EarlyStopping(patience=3, restore_best_weights=True, monitor="val_accuracy"),
    ]
    history = model.fit(train_ds, validation_data=val_ds, epochs=epochs, callbacks=callbacks, verbose=0)
    meta = {
        "type": "image",
        "trained_at": now_iso(),
        "directory": directory,
        "class_names": class_names,
        "history": {k: [float(v) for v in vals] for k, vals in history.history.items()},
    }
    save_model(model, meta)
    return meta

